// 1. 获取 Webhook 传来的参数
const input = $input.item.json.body || $input.item.json || {};
const language = input.language || 'zh';
const outputLanguage = input.outputLanguage || (language === 'en' ? 'English' : 'Chinese');

function sanitizeThemeImagePrompt(value) {
  return String(value || '')
    .replace(/Do not include[^.\n]*(speech bubbles|dialogue balloons|thought bubbles|comic bubbles|text boxes|blank white panels|whiteboards|posters|visual container)[^.\n]*\.?/gi, '')
    .replace(/Absolutely no visible text[^.\n]*\.?/gi, '')
    .replace(/No text,\s*no speech bubbles,\s*no posters,\s*no writing of any kind\.?/gi, 'Textless visual illustration.')
    .replace(/no written whiteboard,\s*no poster text,\s*no speech bubbles\.?/gi, '')
    .replace(/speech bubbles|dialogue balloons|thought bubbles|comic bubbles|callout bubbles|text boxes|empty caption boxes|blank white panels|white rounded rectangles|empty rounded rectangles|blank whiteboards|blank posters|blank signs|whiteboards|posters|display boards|presentation boards|UI panels|comic panels|frames reserved for text|visual containers? designed to hold text/gi, '')
    .replace(/cj_vector_style,?\s*textless full-bleed course-cover illustration,?\s*one continuous immersive scene across the whole canvas,?\s*theme-specific environment and props from the prompt only,?/gi, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const fallbackPrompt = outputLanguage === 'English'
  ? 'A textless flat vector course-cover illustration based on the provided course theme, using only theme-specific scenery, props, icons, and atmosphere.'
  : '根据课程主题生成无文字扁平矢量封面插画，只使用与主题直接相关的场景、道具、图标和氛围。';

const rawPrompt = sanitizeThemeImagePrompt(input.themeImagePrompt || fallbackPrompt);

const stylePositive = [
  'cj_vector_style',
  'textless full-bleed course-cover illustration',
  'one continuous immersive scene across the whole canvas',
  'theme-specific environment and props from the prompt only',
  'flat vector illustration, even black outline, single-line style, 2D flat design',
  'low-saturation solid colors, soft harmonious palette, clean friendly environmental line art',
  'rich background details fill the canvas, balanced composition, fully illustrated edges',
  'character-free scenery, prop-focused environment, empty of living figures'
].join(', ');

const imagePrompt = [stylePositive, rawPrompt].filter(Boolean).join(', ');

// Keep these only in the negative prompt. Repeating object names in the positive prompt makes the model draw them.
const negativePrompt = [
  'readable writing, typography, letters, words, numbers, Chinese characters, English words',
  'captions, labels, title, logo, watermark, poster-like writing, classroom writing',
  'comic layout, worksheet layout, presentation layout, interface layout, template layout',
  'large blank geometric areas, empty placeholder areas, separated layout regions',
  'people, humans, characters, animals, blurry, 3d, realistic, complex textures, bad anatomy, deformed, shadows, gradients'
].join(', ');

// 2. 生成随机种子
const seed = Math.floor(Math.random() * 1000000000000);

// 3. 构建 ComfyUI 工作流。保留低强度场景 LoRA 统一画风，但让课程主题主导画面内容。
const workflow = {
  "1": {
    "inputs": {
      "unet_name": "z_image_turbo_bf16.safetensors",
      "weight_dtype": "default"
    },
    "class_type": "UNETLoader"
  },
  "2": {
    "inputs": {
      "vae_name": "ae.safetensors"
    },
    "class_type": "VAELoader"
  },
  "3": {
    "inputs": {
      "clip_name": "qwen_3_4b.safetensors",
      "type": "lumina2",
      "device": "default"
    },
    "class_type": "CLIPLoader"
  },
  "4": {
    "inputs": {
      "shift": 3,
      "model": [ "1", 0 ]
    },
    "class_type": "ModelSamplingAuraFlow"
  },
  "5": {
    "inputs": {
      "width": 1968,
      "height": 1152,
      "batch_size": 1
    },
    "class_type": "EmptySD3LatentImage"
  },
  "7": {
    "inputs": {
      "text": negativePrompt,
      "clip": [ "101", 1 ]
    },
    "class_type": "CLIPTextEncode"
  },
  "101": {
    "inputs": {
      "lora_name": "poppy.safetensors",
      "strength_model": 0.35,
      "strength_clip": 0.45,
      "model": [ "4", 0 ],
      "clip": [ "3", 0 ]
    },
    "class_type": "LoraLoader"
  },
  "102": {
    "inputs": {
      "text": imagePrompt,
      "clip": [ "101", 1 ]
    },
    "class_type": "CLIPTextEncode"
  },
  "103": {
    "inputs": {
      "seed": seed,
      "steps": 20,
      "cfg": 1.5,
      "sampler_name": "euler",
      "scheduler": "simple",
      "denoise": 1,
      "model": [ "101", 0 ],
      "positive": [ "102", 0 ],
      "negative": [ "7", 0 ],
      "latent_image": [ "5", 0 ]
    },
    "class_type": "KSampler"
  },
  "104": {
    "inputs": {
      "samples": [ "103", 0 ],
      "vae": [ "2", 0 ]
    },
    "class_type": "VAEDecode"
  },
  "105": {
    "inputs": {
      "filename_prefix": "Course_Theme",
      "images": [ "104", 0 ]
    },
    "class_type": "SaveImage"
  }
};

return {
  comfyuiPayload: {
    "prompt": workflow
  }
};

const promptId = $input.item.json.prompt_id;
const comfyUrl = "https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com";
const maxAttempts = 600;

for (let i = 0; i < maxAttempts; i++) {
  await new Promise(r => setTimeout(r, 3000));
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${comfyUrl}/history/${promptId}`,
      json: true
    });

    const taskData = Object.values(res)[0];

    if (taskData && taskData.outputs) {
      let images = [];
      // 动态遍历所有 output 节点，寻找里面包含 images 数组的节点
      for (const nodeId in taskData.outputs) {
        if (taskData.outputs[nodeId].images && taskData.outputs[nodeId].images.length > 0) {
          images = taskData.outputs[nodeId].images;
          break; // 找到图片就立刻停止遍历
        }
      }

      // 如果找到了图片，就拼接 URL 并返回
      if (images.length > 0) {
        const img = images[0];
        const imageUrl = `${comfyUrl}/view?filename=${img.filename}&subfolder=${img.subfolder || ''}&type=${img.type || 'output'}`;
        return { themeImageUrl: imageUrl };
      }
    }

    if (taskData?.status?.status_str === 'error') {
      return { themeImageUrl: null, error: '图片生成失败(ComfyUI内部报错)' };
    }
  } catch (e) {
    console.log("轮询报错，继续重试:", e.message);
  }
}

return { themeImageUrl: null, error: '图片生成超时' };
